// api.ts

import { System } from "aquario-models";
import axios from "axios";

const API_BASE_URL = `http://${process.env.REACT_APP_API_HOST}:${process.env.REACT_APP_API_PORT}`; // Replace with actual IP and port

export const socket = new WebSocket(
  `ws://${process.env.REACT_APP_API_HOST}:3001`
);

const callbacks: ((event: MessageEvent<any> & System.Update) => void)[] = [];

export const onMessage = (
  callback: (event: MessageEvent<any> & System.Update) => void
) => {
  callbacks.push(callback);
  socket.onmessage = function (event: MessageEvent<any> & System.Update) {
    console.log(`[message] Data received from server: ${event.data}`);
    callbacks.forEach((cb) => cb(event));
  };
};

export const runWaterChange = async ({
  tank_id,
}: {
  tank_id?: string | number;
}): Promise<void> => {
  try {
    socket &&
      socket.send(
        JSON.stringify({
          action: System.ServiceRequest.START_WATER_CHANGE,
          data: { tank_id },
        })
      );
    // const response = await axios.get<void>(
    //   `${API_BASE_URL}/maintenance/change/${tank_id}`
    // );
    // return response.data;
  } catch (error) {
    console.error("Error adding feeding log", error);
    throw error;
  }
};

