export const drainTank = async ({
  tank_id,
}: {
  tank_id?: string | number;
}): Promise<void> => {
  try {
    socket.send(
      JSON.stringify({
        action: System.ServiceRequest.START_DRAIN_TANK,
        data: { tank_id },
      })
    );
    const response = await axios.get<void>(
      `${API_BASE_URL}/maintenance/drain/${tank_id}`
    );
    return response.data;
  } catch (error) {
    console.error("Error starting tank drain", error);
    throw error;
  }
};

