import AppBar from "@mui/material/AppBar";
import Box from "@mui/material/Box";
import Toolbar from "@mui/material/Toolbar";
import ThermostatIcon from "@mui/icons-material/Thermostat";
import WarningIcon from "@mui/icons-material/Warning";
import { useEffect, useState } from "react";
import { Button, Icon, Typography } from "@mui/material";
import { System, Tank } from "aquario-models";
import { getTankDetails } from "../../dal/Tank.dal";
import { onMessage, socket } from "../../dal/Maintenance.dal";

interface TankTempBarProps {
  tankDetails?: Partial<Tank>;
  currentTemp?: number;
}

const dangerLevel = ({
  currentTemp,
  lower_temp_limit,
  upper_temp_limit,
}: {
  currentTemp: number;
  lower_temp_limit: number;
  upper_temp_limit: number;
}) => {
  if (currentTemp < lower_temp_limit - 5) {
    return "dangerously cold";
  } else if (currentTemp < lower_temp_limit - 2.5) {
    return "very cold";
  } else if (currentTemp < lower_temp_limit) {
    return "cold";
  } else if (currentTemp > upper_temp_limit + 3) {
    return "dangerously warm";
  } else if (currentTemp > upper_temp_limit + 1.5) {
    return "very warm";
  } else if (currentTemp > upper_temp_limit) {
    return "warm";
  } else {
    return "ideal";
  }
};

const temperatureGaugeColor = ({
  currentTemp,
  lower_temp_limit,
  upper_temp_limit,
}: {
  currentTemp: number;
  lower_temp_limit: number;
  upper_temp_limit: number;
}) => {
  const danger = dangerLevel({
    currentTemp,
    lower_temp_limit,
    upper_temp_limit,
  });
  switch (danger) {
    case "dangerously cold":
      return "indigo";
    case "very cold":
      return "blue";
    case "cold":
      return "cyan";
    case "dangerously warm":
      return "red";
    case "very warm":
      return "orange";
    case "warm":
      return "yellow";
    default:
      return "lime";
  }
};

export const showWaterTemp: React.FC<TankTempBarProps> = ({
  tankDetails,
  currentTemp,
}: TankTempBarProps) => {
  const lower_temp_limit = tankDetails?.settings?.lower_temp_limit || 25,
    upper_temp_limit = tankDetails?.settings?.upper_temp_limit || 30;
  if (currentTemp) {
    const currentTempC = Math.round(currentTemp);
    const currentTempF = Math.round(currentTemp * 1.8 + 32);
    const danger = dangerLevel({
      currentTemp,
      lower_temp_limit,
      upper_temp_limit,
    });
    return (
      <Box display={"flex"} width={"100%"} justifyContent={"center"}>
        <Box flex={"auto 1 1"} textAlign={"center"}></Box>
        <Box flex={"auto 1 1"} textAlign={"center"}>
          <Button
            sx={{
              alignItems: "middle",
              color: temperatureGaugeColor({
                currentTemp,
                lower_temp_limit,
                upper_temp_limit,
              }),
            }}
          >
            <ThermostatIcon />
            <strong>{currentTempC}°C</strong>&nbsp;&nbsp;/&nbsp;&nbsp;
            <strong>{currentTempF}°F</strong>
          </Button>
          <Box
            flex={"auto 1 1"}
            display={"flex"}
            textAlign={"center"}
            justifyContent={"center"}
            alignItems={"center"}
          >
            {(currentTemp > upper_temp_limit ||
              currentTemp < lower_temp_limit) && (
              <WarningIcon
                htmlColor="yellow"
                fontSize="small"
                sx={{ ml: 1, height: "8pt", width: "8pt" }}
              />
            )}
            <Typography
              color={danger == "ideal" ? "lime" : "yellow"}
              fontSize={8}
              sx={{ ml: 0.25, mr: 1 }}
              variant="button"
            >
              {danger}
            </Typography>
          </Box>
        </Box>
        <Box flex={"auto 1 1"} textAlign={"center"}></Box>
      </Box>
    );
  } else {
    return (
      <Button sx={{ alignItems: "middle" }}>
        <ThermostatIcon htmlColor="white" />
        <WarningIcon color="warning" />
      </Button>
    );
  }
};

export const TankTempBar: React.FC<TankTempBarProps> = ({ tankDetails }) => {
  const [currentTemp, setCurrentTemp] = useState(0);
  const [tankData, setTankData] = useState(tankDetails || {});

  useEffect(() => {
    const interval = setInterval(() => handleUpdateTemp(), 5000);

    if (!currentTemp) {
      handleUpdateTemp();
    }

    fetchTankData();

    return () => {
      interval && clearInterval(interval);
    };
  }, []); // Empty dependency array to run only on mount

  const fetchTankData = async () => {
    if (tankDetails?.id) {
      await getTankDetails(tankDetails?.id || "").then((tank) => {
        if (tank) {
          setTankData(tank);
        }
      });
    }
  };

  onMessage(function (event: MessageEvent<any>) {
    const message =
      event.data.includes("{") && (JSON.parse(event.data) as System.Update);
    if (message && message.action === System.ParameterUpdate.TEMPERATURE) {
      setCurrentTemp(message.data.average);
    }
  });

  const handleUpdateTemp = async () => {
    const message = {
      action: System.ParameterCheck.TEMPERATURE,
      data: { tank_id: tankData.id },
    };
    socket.send(JSON.stringify(message));
  };

  return (
    <Box>
      <AppBar position="fixed" color="primary" sx={{ top: "auto", bottom: 0 }}>
        <Toolbar
          variant="dense"
          sx={{
            backgroundColor: "black",
            display: "flex",
            justifyContent: "space-around",
          }}
        >
          {showWaterTemp({ tankDetails, currentTemp })}
        </Toolbar>
      </AppBar>
    </Box>
  );
};

export default TankTempBar;
