import React, { useEffect, useState } from "react";
import { Avatar, Box, Card, Stack, Typography } from "@mui/material";
import { useParams } from "react-router-dom";
import { getAnimalDetails } from "../dal/Animal.dal";
import { styled } from "@mui/material/styles";
import AnimalAppBar from "../components/AppBar/Animal";
import FeedingDialog from "../components/FeedingDialog";
import DescriptionIcon from "@mui/icons-material/Description";
import LunchDiningIcon from "@mui/icons-material/LunchDining";
import ClockIcon from "@mui/icons-material/PunchClock";
import tempImage from "../assets/axie-cakepop.jpg"; // Adjust the path as necessary
import { addFeedingLog } from "../dal/Log.dal";
import FeedingLogs from "../components/FeedingLogs";
import TankTempBar from "../components/AppBar/TankTemp";
import { getTankDetails } from "../dal/Tank.dal";
import { Animal, Log, Tank } from "aquario-models";
import { DateTime } from "luxon";

interface AnimalProps {
  animal?: Animal;
  logs?: any[];
}

const Item = styled(Typography)(({ theme }) => ({
  padding: theme.spacing(1),
  textAlign: "center",
  lineHeight: "1",
}));

const AnimalDetail: React.FC<AnimalProps> = (props: AnimalProps) => {
  const [currentTime, setCurrentTime] = useState(new Date());

  // const [nextWaterChange, setNextWaterChange] = useState<Date | null>(null);
  const [settingsOpen, setSettingsOpen] = useState(false);
  // const [animalAnimals, setAnimalAnimals] = useState<Animal[]>([]);
  // const [animalLogs, setAnimalLogs] = useState<any[]>([]);
  const [latestFeeding, setLatestFeeding] = useState<Log | null>(null);
  const [feedingDialog, toggleFeedingDialog] = useState<boolean>(false);
  const [feedingLogDialog, toggleFeedingLog] = useState<boolean>(false);
  const [tankDetails, setTankDetails] = useState<Tank>({
    id: "",
    service_status: 0,
    settings: {
      volume: 0,
      vol_unit: "gallons",
      drain_time: 0,
      fill_time: 0,
      res_fill_time: 0,
      has_reservoir: false,
      lower_temp_limit: 0,
      upper_temp_limit: 0,
    },
  });
  const [animalDetails, setAnimalDetails] = useState<{
    animal: Animal;
    logs?: any[];
  }>({
    animal: {
      id: "",
      tank_id: "",
      name: "",
      species: "",
      species_latin: "",
      last_feeding_log: {
        timestamp: new Date().toISOString(),
        log_type: "null",
        log_json: "{}",
      },
    },
    logs: [],
  });
  const animal_id = useParams<{ animal_id: string }>().animal_id;

  // Fetch the animal details
  const fetchAnimal = async () => {
    try {
      const data = await getAnimalDetails(animal_id);
      console.log(data);
      // const log_json = JSON.parse(data.animal.last_feeding_log.log_json);
      // data.animal.last_feeding_log.food_type = log_json.food_type;
      // data.animal.last_feeding_log.food_quantity = log_json.quantity;
      setAnimalDetails(data);
      setLatestFeeding(data.logs[0]);
      if (data.animal.enclosure_id) {
        fetchTank(data.animal.enclosure_id);
      }
    } catch (error) {
      console.error("Failed to fetch animals:", error);
    }
  };

  const fetchTank = async (tank_id: string) => {
    try {
      const data = await getTankDetails(tank_id);
      console.log(data);
      // const log_json = JSON.parse(data.animal.last_feeding_log.log_json);
      // data.animal.last_feeding_log.food_type = log_json.food_type;
      // data.animal.last_feeding_log.food_quantity = log_json.quantity;
      setTankDetails(data);
    } catch (error) {
      console.error("Failed to fetch animals:", error);
    }
  };

  useEffect(() => {
    setInterval(() => {
      setCurrentTime(new Date());
    }, 1000);

    fetchAnimal();
  }, [animal_id]); // Empty dependency array to run only on mount

  // if (!props.animals) {
  //   setAnimalAnimals([]);
  // }

  const handleFeedClick = () => {
    toggleFeedingDialog(!feedingDialog);
  };

  const handleLogsClick = () => {
    toggleFeedingLog(!feedingLogDialog);
  };

  const addLog = async (log_json: string) => {
    await addFeedingLog({
      animal_id,
      action_type: "Feeding",
      container_id: animalDetails.animal.tank_id,
      log_json,
    });

    const data = await getAnimalDetails(animal_id);
    setAnimalDetails(data);
    setLatestFeeding(data.logs[0]);
  };

  useEffect(() => {}, []);

  return (
    <React.Fragment>
      <AnimalAppBar animalDetails={animalDetails.animal}></AnimalAppBar>
      <FeedingLogs
        animalDetails={animalDetails.animal}
        logs={animalDetails.logs}
        open={feedingLogDialog}
        onClose={() => toggleFeedingLog(false)}
      />
      <FeedingDialog
        animalDetails={animalDetails.animal}
        open={feedingDialog}
        onClose={() => toggleFeedingDialog(false)}
        onSave={addLog}
      />
      <Stack
        direction="row"
        justifyContent="space-around"
        alignItems="flex-start"
        height="100%"
      >
        <Stack
          spacing={2}
          direction="column"
          justifyContent="center"
          alignItems="center"
          flexGrow={1}
          padding={"24px"}
        >
          <Typography
            variant="button"
            fontSize={28}
            textAlign="center"
            justifyContent="center"
            alignItems="center"
          >
            {animalDetails?.animal.name}
          </Typography>
          <Avatar
            alt={animalDetails?.animal.name}
            src={tempImage}
            sx={{ width: 128, height: 128 }}
          />
          <Typography
            variant="button"
            fontSize={18}
            textAlign="center"
            color={"grey"}
          >
            {animalDetails?.animal.species}
          </Typography>
          <Typography
            fontSize={18}
            fontStyle={"italic"}
            textAlign="center"
            marginTop={0}
            color={"grey"}
            style={{ marginTop: 0 }}
          >
            {animalDetails?.animal.species_latin}
          </Typography>

          <Item variant="button">{animalDetails?.animal.notes}</Item>
        </Stack>
        <Stack spacing={2} direction="column" padding={"24px"}>
          <Card
            sx={{
              backgroundColor: "grey",
              padding: "20px 60px",
              marginTop: "10px",
              borderRadius: "15px",
              flexShrink: 1,
              flexGrow: 0,
            }}
          >
            <Typography
              variant="button"
              fontSize={12}
              display="flex"
              justifyContent={"center"}
              alignItems={"center"}
              onClick={handleLogsClick}
            >
              <DescriptionIcon
                sx={{
                  mr: 1,
                  width: "24px",
                  height: "24px",
                  lineHeight: "12pt",
                }}
              />{" "}
              View Feeding Logs
            </Typography>
          </Card>
          <Card
            sx={{
              backgroundColor: "green",
              padding: "50px",
              marginTop: "10px",
              borderRadius: "15px",
              textAlign: "center",
              flex: "100% 0 1",
            }}
          >
            <Typography
              variant="button"
              fontSize={24}
              display="flex"
              justifyContent={"center"}
              alignItems={"center"}
              onClick={handleFeedClick}
            >
              <LunchDiningIcon sx={{ mr: 1, width: "48px", height: "48px" }} />
              Feed
            </Typography>
          </Card>
          {latestFeeding && (
            <Typography
              variant="button"
              fontSize={12}
              display="flex"
              justifyContent={"center"}
              alignItems={"center"}
              onClick={handleFeedClick}
            >
              <ClockIcon sx={{ mr: 1, width: "24px", height: "24px" }} />
              {"Last Fed"}
              {latestFeeding?.log_json ? " " : ""}
              {latestFeeding.log_json.quantity > 1
                ? latestFeeding.log_json.quantity
                : "a"}{" "}
              {latestFeeding?.log_json?.food_type}
              {latestFeeding?.log_json?.quantity > 1 ? "s" : ""} at{" "}
              {DateTime.fromSQL(latestFeeding?.timestamp)}
            </Typography>
          )}
        </Stack>
        {tankDetails.id && (
          <TankTempBar tankDetails={tankDetails}></TankTempBar>
        )}
      </Stack>
    </React.Fragment>
  );
};

export default AnimalDetail;
