import React, { useEffect, useRef, useState } from "react";
import { useNavigate } from "react-router-dom";
import { Avatar, Button, IconButton, Stack, Typography } from "@mui/material";
import SettingsDialog from "../components/SettingsDialog";
import { useParams } from "react-router-dom";
import {
  getAnimalsForTank,
  getLogsForTank,
  getTankDetails,
  updateTankSettings,
} from "../dal/Tank.dal";
import { styled } from "@mui/material/styles";
import TankAppBar from "../components/AppBar/Tank";
import {
  drainTank,
  fillTank,
  onMessage,
  reset,
  runWaterChange,
  serviceStatus,
  socket,
} from "../dal/Maintenance.dal";
import CircularProgress from "@mui/material/CircularProgress";
import { Animal, System, Tank, TankSettings } from "aquario-models";
import tempImage from "../assets/axie-cakepop.jpg"; // Adjust the path as necessary
import TankTempBar from "../components/AppBar/TankTemp";
import SettingsIcon from "@mui/icons-material/Settings";

interface TankProps {
  tank_id?: string | number;
  animals?: Animal[];
  logs?: any[];
}

const Item = styled(Typography)(({ theme }) => ({
  padding: theme.spacing(1),
  textAlign: "center",
  lineHeight: "1",
}));

const TankDetail: React.FC<TankProps> = (props: TankProps) => {
  const navigate = useNavigate();
  const [currentTemp, setCurrentTemp] = useState<number | null>(null);
  const [serviceStatus, setStatus] = useState(System.State.IDLE);
  const serviceStatusRef = useRef(serviceStatus);
  const [waterChangeInProgress, setWaterChangeState] = useState(false);
  const [settingsOpen, setSettingsOpen] = useState(false);
  const [tankSettings, setTankSettings] = useState<TankSettings>({});
  const [tankAnimals, setTankAnimals] = useState<Animal[]>([]);
  const [tankLogs, setTankLogs] = useState<any[]>([]);
  const [waterChangeProgress, setWaterChangeProgress] = useState<number>(0);
  const [drainProgress, setDrainProgress] = useState<number>(0);
  const [fillProgress, setFillProgress] = useState<number>(0);
  const fillProgressRef = useRef(fillProgress);
  const drainProgressRef = useRef(drainProgress);
  const waterChangeProgressRef = useRef(waterChangeProgress);
  const [tankDetails, setTankDetails] = useState<Tank>({
    id: "",
    service_status: System.State.IDLE,
    settings: {
      volume: 0,
      vol_unit: "gallons",
      drain_time: 0,
      fill_time: 0,
      res_fill_time: 0,
      has_reservoir: false,
      lower_temp_limit: 0,
      upper_temp_limit: 0,
    },
  });
  const tank_id = useParams<{ tank_id: string }>().tank_id;

  const initSocket = () => {
    if (socket) {
      socket.onopen = function (event: Event) {
        console.log("[open] Connection established");
        console.log("Sending to server");
      };
      onMessage(function (event: MessageEvent<any> & System.Update) {
        console.log(`[message] Data received from server: ${event.data}`);
        try {
          const messageData = JSON.parse(event.data);
          if (
            messageData.action === System.ServiceUpdate.WATER_CHANGE_COMPLETE
          ) {
            console.log("Water change complete");
            setStatus(System.State.IDLE);
            setWaterChangeState(false);
            setWaterChangeProgress(100);
          } else if (
            messageData.action === System.ServiceUpdate.FILL_COMPLETE
          ) {
            console.log("Fill complete");
            setStatus(System.State.IDLE);
          } else if (
            messageData.action === System.ServiceUpdate.DRAIN_COMPLETE
          ) {
            console.log("Drain complete");
            setStatus(System.State.IDLE);
          } else if (
            messageData.action === System.ServiceUpdate.WATER_CHANGE_BEGAN
          ) {
            console.log("Water change began");
            setWaterChangeState(true);
            setWaterChangeProgress(0);
          } else if (messageData.action === System.ServiceUpdate.FILL_BEGAN) {
            if (waterChangeInProgress) {
              setStatus(System.State.WATER_CHANGE_FILLING_TANK);
            } else {
              setStatus(System.State.FILLING_TANK);
            }
            setFillProgress(0);
          } else if (messageData.action === System.ServiceUpdate.DRAIN_BEGAN) {
            if (waterChangeInProgress) {
              setStatus(System.State.WATER_CHANGE_DRAINING);
            } else {
              setStatus(System.State.DRAINING);
            }
            setDrainProgress(100);
          } else if (messageData.action === System.ServiceUpdate.STATE_RESET) {
            console.log("State reset");
            setStatus(System.State.IDLE);
          }
        } catch (error) {
          console.error("Error parsing message data", error);
        }
      });
    } else {
      console.error("Socket is not open");
      initSocket();
    }
  };

  const fetchTank = async () => {
    try {
      const data = await getTankDetails(tank_id);
      setTankDetails(data);
      if (data) {
        setStatus(data.service_status);
      }
    } catch (error) {
      console.error("Failed to fetch tanks:", error);
    }
  };

  const fetchTankAnimals = async () => {
    try {
      const data = await getAnimalsForTank(tank_id);
      setTankAnimals(data);
    } catch (error) {
      console.error("Failed to fetch tanks:", error);
    }
  };

  const fetchTankLogs = async () => {
    try {
      const data = await getLogsForTank(tank_id);
      setTankLogs(data);
    } catch (error) {
      console.error("Failed to fetch tanks:", error);
    }
  };

  let loadingInterval: NodeJS.Timeout;

  useEffect(() => {
    serviceStatusRef.current = serviceStatus;
    fillProgressRef.current = fillProgress;
    drainProgressRef.current = drainProgress;
    waterChangeProgressRef.current = waterChangeProgress;
  }, [serviceStatus, drainProgress, fillProgress, waterChangeProgress]);

  useEffect(() => {
    // Fetch the list of tanks when the component mounts
    setInterval(() => {
      let iServiceStatus = serviceStatusRef.current;
      if (iServiceStatus === System.State.WATER_CHANGE_DRAINING) {
        const drainTime = tankDetails?.settings?.drain_time || 1;
        const progress = (100 / drainTime) * 2;
        console.log("Drain Progress: ", drainProgressRef.current, progress);
        setDrainProgress(drainProgressRef.current - progress);
      } else if (iServiceStatus === System.State.WATER_CHANGE_FILLING_TANK) {
        const fillTime = tankDetails?.settings?.fill_time || 1;
        const progress = 100 / fillTime;
        setFillProgress(fillProgressRef.current + progress / 2);
      } else if (iServiceStatus === System.State.FILLING_TANK) {
        const fillTime = tankDetails?.settings?.fill_time || 1;
        const progress = 100 / fillTime;
        setFillProgress(fillProgressRef.current + progress / 2);
      } else if (iServiceStatus === System.State.DRAINING) {
        const drainTime = tankDetails?.settings?.drain_time || 1;
        const progress = 100 / drainTime;
        setDrainProgress(drainProgressRef.current - progress / 2);
      } else {
        setWaterChangeState(false);
        setDrainProgress(0);
        setFillProgress(0);
      }
    }, 500);
    fetchTank();
    fetchTankAnimals();
    fetchTankLogs();
    initSocket();
    return () => {
      console.log("Component will unmount");
      clearInterval(loadingInterval);
    };
  }, []); // Empty dependency array to run only on mount

  // if (!props.animals) {
  //   setTankAnimals([]);
  // }

  const openAnimalPage = (animal_id?: string) => {
    navigate(`/animal/${animal_id}`);
  };

  const handleSettingsSave = (settings: TankSettings) => {
    const tankSettings = {
      ...tankDetails.settings,
      ...settings,
    };
    setTankSettings(tankSettings);
    updateTankSettings({ ...tankDetails, settings: tankSettings });
  };

  const handleWaterChange = async () => {
    await runWaterChange({ tank_id });
  };
  const handleDrainTank = async () => {
    await drainTank({ tank_id });
  };
  const handleFillTank = async () => {
    await fillTank({ tank_id });
  };

  const handleCancel = async () => {
    await reset({ tank_id });
  };

  // const handleScheduleChange = (day: number, time: string) => {
  //   const currentTime = new Date();
  //   const nextChange = new Date();

  //   nextChange.setDate(
  //     currentTime.getDate() + ((7 + day - currentTime.getDay()) % 7)
  //   );
  //   const [hours, minutes] = time.split(":").map(Number);
  //   nextChange.setHours(hours, minutes, 0, 0);

  //   // If the calculated time is in the past, schedule it for the next week
  //   if (nextChange <= currentTime) {
  //     nextChange.setDate(nextChange.getDate() + 7);
  //   }

  //   // setNextWaterChange(nextChange);
  // };

  return (
    <React.Fragment>
      <SettingsDialog
        open={settingsOpen}
        settings={tankDetails.settings}
        onClose={() => setSettingsOpen(false)}
        onSave={handleSettingsSave}
      />
      <TankAppBar
        tankDetails={tankDetails}
        currentTemp={currentTemp}
      ></TankAppBar>
      <Stack direction="column" justifyContent="center">
        <Item variant="button">Animals</Item>
        <Stack
          spacing={2}
          direction="row"
          justifyContent={"center"}
          sx={{ padding: "0 16px", mt: 1, mb: 2, color: "#aabbff" }}
        >
          {tankAnimals.map((animal) => (
            <Button
              color="inherit"
              variant="outlined"
              key={animal.id}
              onClick={() => openAnimalPage(animal.id)}
            >
              <Stack direction={"row"} alignItems={"center"}>
                <Avatar
                  alt={animal.name}
                  src={tempImage}
                  sx={{ width: 48, height: 48, mt: 2, mb: 2, mr: 2 }}
                />
                {animal.name}
              </Stack>
            </Button>
          ))}

          {tankAnimals.length === 0 && (
            <Item variant="button">No animals in this tank</Item>
          )}
        </Stack>
      </Stack>
      <Stack direction="column" justifyContent="center">
        <Item variant="button">
          Maintenance{" "}
          <IconButton onClick={() => setSettingsOpen(true)}>
            <SettingsIcon sx={{ width: 16, height: 16 }} />
          </IconButton>
        </Item>
        <Stack
          spacing={2}
          direction="row"
          sx={{ padding: "0 16px", mt: 1, color: "#aabbff" }}
        >
          <Button
            size="large"
            variant={
              serviceStatus > System.State.IDLE && !waterChangeInProgress
                ? "contained"
                : "outlined"
            }
            color="inherit"
            fullWidth
            onClick={handleWaterChange}
            disabled={serviceStatus > System.State.IDLE}
          >
            {waterChangeInProgress && (
              <CircularProgress
                size={20}
                sx={{ mr: 2, color: "#aa00aa" }}
                variant="determinate"
                value={waterChangeProgress}
              />
            )}
            {waterChangeInProgress ? "Changing Water" : "Change Water"}
          </Button>
          <Button
            size="large"
            variant={
              serviceStatus !== System.State.FILLING_TANK &&
              serviceStatus > System.State.IDLE
                ? "contained"
                : "outlined"
            }
            color="inherit"
            fullWidth
            onClick={handleFillTank}
            disabled={serviceStatus > System.State.IDLE}
          >
            {serviceStatus === System.State.FILLING_TANK && (
              <CircularProgress
                size={20}
                sx={{ mr: 2, color: "#00bbff" }}
                variant="determinate"
                value={fillProgress}
              />
            )}
            {serviceStatus === System.State.FILLING_TANK
              ? "Filling Tank"
              : "Fill Tank"}
          </Button>
          <Button
            size="large"
            variant={
              serviceStatus !== System.State.DRAINING &&
              serviceStatus > System.State.IDLE
                ? "contained"
                : "outlined"
            }
            color="inherit"
            fullWidth
            onClick={handleDrainTank}
            disabled={serviceStatus > System.State.IDLE}
          >
            {serviceStatus === System.State.DRAINING && (
              <CircularProgress
                size={20}
                sx={{ mr: 2, color: "#ff4400" }}
                variant="determinate"
                value={drainProgress}
              />
            )}
            {serviceStatus === System.State.DRAINING
              ? "Draining Tank"
              : "Drain Tank"}
          </Button>
        </Stack>
        <Stack
          spacing={2}
          direction="row"
          sx={{ padding: "0 16px", mt: 1, color: "#aabbff" }}
        >
          {serviceStatus > System.State.IDLE && (
            <Button
              size="large"
              variant={
                serviceStatus !== System.State.DRAINING &&
                serviceStatus > System.State.IDLE
                  ? "contained"
                  : "outlined"
              }
              color="inherit"
              fullWidth
              onClick={handleCancel}
            >
              Cancel Job
            </Button>
          )}
        </Stack>
        {tankDetails?.id && (
          <TankTempBar tankDetails={tankDetails}></TankTempBar>
        )}
      </Stack>
    </React.Fragment>
  );
};

export default TankDetail;
